solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char *my_strdup(const char *src) {
    size_t len = strlen(src);
    char *dst = malloc(len + 1);
    if (!dst) return NULL;
    strcpy(dst, src);
    return dst;
}

int main(void) {
    const char *original = "Bonjour";
    char *copie = my_strdup(original);
    if (!copie) return 1;
    printf("original : %s\n", original);
    printf("copie    : %s\n", copie);
    copie[0] = 'b';
    printf("Apres modif copie :\n");
    printf("original : %s\n", original);
    printf("copie    : %s\n", copie);
    printf("len = %zu\n", strlen(copie));
    free(copie);
    return 0;
}

