/* == EXEMPLE ================================================
 * Duplication d'un tableau d'entiers sur le heap
 * Pattern : malloc(n * sizeof) + memcpy
 * =========================================================== */
int *dup_array(const int *src, int n) {
    int *dst = malloc(n * sizeof(int));
    if (!dst) return NULL;
    memcpy(dst, src, n * sizeof(int));
    return dst;
}
void example_demo(void) {
    int orig[] = {10, 20, 30};
    int *copy = dup_array(orig, 3);
    copy[0] = 99;
    printf("orig[0]=%d copy[0]=%d\n", orig[0], copy[0]);
    free(copy);
}
